export class AdminComponent {
  // ── Computed ──────────────────────────────
  get totalArrecadado() {
    return this.presentesRecebidos.filter(p => p.statusPagamento === 'PAGO').reduce((s, p) => s + p.total, 0);
  }
  get mensagens() {
    return this.presentesRecebidos.filter(p => p.mensagem && p.mensagem.trim());
  }
  get ultimosPresentes() {
    return [...this.presentesRecebidos].reverse().slice(0, 5);
  }
  get confirmados() {
    return this.convites.flatMap(c => c.convidados).filter(g => g.status === 'CONFIRMADO').length;
  }
  get pendentes() {
    return this.convites.flatMap(c => c.convidados).filter(g => g.status === 'PENDENTE').length;
  }
  get talvez() {
    return this.convites.flatMap(c => c.convidados).filter(g => g.status === 'TALVEZ').length;
  }
  get naoVem() {
    return this.convites.flatMap(c => c.convidados).filter(g => g.status === 'NAO_VEM').length;
  }
  constructor(auth, catalogoSvc, presenteRecebidoS, conviteSvc, toastSvc) {
    this.auth = auth;
    this.catalogoSvc = catalogoSvc;
    this.presenteRecebidoS = presenteRecebidoS;
    this.conviteSvc = conviteSvc;
    this.toastSvc = toastSvc;
    // ── Auth ──────────────────────────────────
    this.loginUser = '';
    this.loginPass = '';
    this.loginErr = '';
    this.logging = false;
    // ── Tab ───────────────────────────────────
    this.activeTab = 'dashboard';
    // ── Catálogo ──────────────────────────────
    this.catalogo = [];
    this.showGiftForm = false;
    this.giftForm = {
      nome: '',
      descricao: '',
      valor: 0
    };
    // ── Presentes recebidos ───────────────────
    this.presentesRecebidos = [];
    // ── Convites ──────────────────────────────
    this.convites = [];
    this.showConviteForm = false;
    this.conviteForm = {
      codigo: '',
      familia: '',
      convidadosStr: ''
    };
    //---Convidados------------------------------
    this.showConvidadosForm = false;
    this.convidadosForm = {
      nome: '',
      codigoConvite: ''
    };
    this._editandoConviteId = null;
    // ── Editar convidado inline ───────────────────────────────
    this._editandoConvidadoId = null;
    this.convidadoEditForm = {
      nome: '',
      status: 'PENDENTE',
      codigoConvite: ''
    };
  }
  ngOnInit() {
    if (this.auth.isLoggedIn()) this.loadData();
  }
  // ── Login ─────────────────────────────────
  login() {
    const req = {
      username: this.loginUser,
      password: this.loginPass
    };
    this.logging = true;
    this.loginErr = '';
    this.auth.login(req).subscribe({
      next: () => {
        this.logging = false;
        this.loadData();
      },
      error: () => {
        this.logging = false;
        this.loginErr = 'Usuário ou senha incorretos.';
      }
    });
  }
  logout() {
    this.auth.logout();
  }
  // ── Carregar dados ────────────────────────
  loadData() {
    this.catalogoSvc.listar().subscribe({
      next: c => this.catalogo = c,
      error: () => {}
    });
    this.presenteRecebidoS.listar().subscribe({
      next: p => this.presentesRecebidos = p,
      error: () => {}
    });
    this.conviteSvc.listar().subscribe({
      next: c => this.convites = c,
      error: () => {}
    });
  }
  setTab(tab) {
    this.activeTab = tab;
  }
  // ── Helpers ───────────────────────────────
  confirmadosCount(convite) {
    return convite.convidados.filter(g => g.status === 'CONFIRMADO').length;
  }
  statusClass(status) {
    const map = {
      CONFIRMADO: 'badge--confirm',
      TALVEZ: 'badge--maybe',
      NAO_VEM: 'badge--decline',
      PENDENTE: 'badge--pending'
    };
    return map[status] ?? '';
  }
  statusLabel(status) {
    const map = {
      CONFIRMADO: '✓ Confirmado',
      TALVEZ: '? Talvez',
      NAO_VEM: '✗ Não vem',
      PENDENTE: '⏳ Pendente'
    };
    return map[status] ?? status;
  }
  statusPagLabel(status) {
    const map = {
      PAGO: '✓ Pago',
      PENDENTE: '⏳ Pendente',
      EXPIRADO: '✗ Expirado',
      RECUSADO: '✗ Recusado'
    };
    return map[status] ?? status;
  }
  pagamentoLabel(forma) {
    return forma === 'PIX' ? '📱 Pix' : '💳 Cartão';
  }
  editarConvite(c) {
    this.conviteForm = {
      codigo: c.codigo,
      familia: c.familia,
      convidadosStr: c.convidados.map(g => g.nome).join('\n')
    };
    this._editandoConviteId = c.id;
    this.showConviteForm = true;
    this.activeTab = 'convites';
  }
  // ── Catálogo ──────────────────────────────────────────────
  addPresente() {
    // ...validação...
    this.catalogoSvc.criar({
      ...this.giftForm
    }).subscribe({
      next: p => {
        this.showGiftForm = false;
        this.giftForm = {
          nome: '',
          descricao: '',
          valor: 0
        };
        this.toastSvc.success('"' + p.nome + '" adicionado! 🎁');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao adicionar presente.')
    });
  }
  removePresente(id) {
    if (!confirm('Remover este presente do catálogo?')) return;
    this.catalogoSvc.deletar(id).subscribe({
      next: () => {
        this.toastSvc.success('Presente removido.');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao remover.')
    });
  }
  // ── Convites ──────────────────────────────────────────────
  addConvite() {
    // ...validação e lógica de editar/criar...
    // no next de ambos os branches:
    this.toastSvc.success('Convite criado!'); // ou 'atualizado!'
    this.loadData();
  }
  removeConvite(id) {
    if (!confirm('Remover este convite?')) return;
    this.conviteSvc.deletar(id).subscribe({
      next: () => {
        this.toastSvc.success('Convite removido.');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao remover convite.')
    });
  }
  // ── Convidados ────────────────────────────────────────────
  removerConvidado(conviteId, convidadoId) {
    if (!confirm('Remover este convidado?')) return;
    this.conviteSvc.removerConvidado(convidadoId).subscribe({
      next: () => {
        this.toastSvc.success('Convidado removido.');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao remover convidado.')
    });
  }
  editarConvidado(conv, g) {
    const novoNome = prompt('Editar nome do convidado:', g.nome);
    if (!novoNome?.trim()) return;
    this.conviteSvc.atualizarConvidado(g.id, {
      ...g,
      nome: novoNome.trim()
    }).subscribe({
      next: () => {
        this.toastSvc.success('Convidado atualizado!');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao atualizar convidado.')
    });
  }
  abrirEdicaoConvidado(g) {
    this._editandoConvidadoId = g.id;
    this.convidadoEditForm = {
      nome: g.nome,
      status: g.status,
      codigoConvite: ''
    };
  }
  cancelarEdicaoConvidado() {
    this._editandoConvidadoId = null;
  }
  salvarConvidado(g) {
    if (!this.convidadoEditForm.nome.trim()) return;
    this.conviteSvc.atualizarConvidado(g.id, {
      ...g,
      nome: this.convidadoEditForm.nome.trim(),
      status: this.convidadoEditForm.status
    }).subscribe({
      next: () => {
        this._editandoConvidadoId = null;
        this.toastSvc.success('Convidado atualizado!');
        this.loadData();
      },
      error: () => this.toastSvc.error('Erro ao atualizar convidado.')
    });
  }
  addConvidado() {
    if (!this.convidadosForm.nome.trim() || !this.convidadosForm.codigoConvite) {
      this.toastSvc.error('Preencha nome e selecione um convite.');
      return;
    }
    const dto = {
      nome: this.convidadosForm.nome.trim(),
      conviteId: Number(this.convidadosForm.codigoConvite),
      status: 'PENDENTE'
    };
    this.conviteSvc.criarConvidado(dto).subscribe({
      next: () => {
        this.showConvidadosForm = false;
